          useValue: {
            listCollectionEvents: () =>
              of([
                {
                  eventId: 'event-open',
                  event: {
                    id: 'event-open',
                    name: 'Credenciamento',
                    startDate: openStart.toISOString(),
                    endDate: new Date(openStart.getTime() + 2 * 60 * 60_000).toISOString(),
                    emoji: '✅',
                    type: 'OTHER',
